/**
 * @name FileItem getName() flows to File constructor - ZIP slip / upload path traversal
 * @description Check if uploaded file names flow directly to File constructors
 * @kind path-problem
 * @problem.severity error
 * @id java/upload-filename-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module UploadPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // FileItem.getName() - multipart upload filename
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.fileupload", "FileItem") and
      source.asExpr() = mc
    )
    or
    // FileItem.getString() - file content as string
    exists(MethodCall mc |
      mc.getMethod().hasName("getString") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.fileupload", "FileItem") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module UploadPathFlow = TaintTracking::Global<UploadPathConfig>;
import UploadPathFlow::PathGraph

from UploadPathFlow::PathNode source, UploadPathFlow::PathNode sink
where UploadPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Upload filename flows to file operation from $@.", source.getNode(), "upload filename"

/**
 * @name Upload filename - FileItem.getName() direct flow to File without canonicalization
 * @description FileItem.getName() returns user-controlled filename that can contain path separators
 * @kind path-problem
 * @problem.severity error
 * @id java/fileitem-name-to-file-path
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module FileItemNameConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.fileupload", "FileItem") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // getCanonicalPath, normalize, or other sanitizers
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or
       mc.getMethod().hasName("getCanonicalFile") or
       mc.getMethod().hasName("normalize")) and
      node.asExpr() = mc
    )
  }
}

module FileItemNameFlow = TaintTracking::Global<FileItemNameConfig>;
import FileItemNameFlow::PathGraph

from FileItemNameFlow::PathNode source, FileItemNameFlow::PathNode sink
where FileItemNameFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "FileItem.getName() flows to File constructor without canonicalization from $@.", source.getNode(), "upload filename"
